    def __init__(self, *, model_id:typing.Optional[str], api_key:typing.Optional[str], additional_config:typing.Optional[str]):
        self.model_id = model_id
        self.api_key = api_key
        self.additional_config = additional_config
        
        

    
    def __str__(self):
        return "AnthropicConfig(model_id={}, api_key={}, additional_config={})".format(self.model_id, self.api_key, self.additional_config)
    def __eq__(self, other):
        if self.model_id != other.model_id:
            return False
        if self.api_key != other.api_key:
            return False
        if self.additional_config != other.additional_config:
            return False
        return True

