# AgentError
# We want to define each variant as a nested class that's also a subclass,
# which is tricky in Python.  To accomplish this we're going to create each
# class separately, then manually add the child classes to the base class's
# __dict__.  All of this happens in dummy class to avoid polluting the module
# namespace.
class AgentError(Exception):
    pass

_UniffiTempAgentError = AgentError

class AgentError:  # type: ignore
    
    class Runtime(_UniffiTempAgentError):
        
        def __init__(self, reason, detail):
            super().__init__(", ".join([
                "reason={!r}".format(reason),
                "detail={!r}".format(detail),
            ]))
            self.reason = reason
            self.detail = detail

        def __repr__(self):
            return "AgentError.Runtime({})".format(str(self))
    _UniffiTempAgentError.Runtime = Runtime # type: ignore

AgentError = _UniffiTempAgentError # type: ignore
del _UniffiTempAgentError


class _UniffiFfiConverterTypeAgentError(_UniffiConverterRustBuffer):
    @staticmethod
    def read(buf):
        variant = buf.read_i32()
        if variant == 1:
            return AgentError.Runtime(
                _UniffiFfiConverterString.read(buf),
                _UniffiFfiConverterOptionalString.read(buf),
            )
        raise InternalError("Raw enum value doesn't match any cases")

    @staticmethod
    def check_lower(value):
        if isinstance(value, AgentError.Runtime):
            _UniffiFfiConverterString.check_lower(value.reason)
            _UniffiFfiConverterOptionalString.check_lower(value.detail)
            return

    @staticmethod
    def write(value, buf):
        if isinstance(value, AgentError.Runtime):
            buf.write_i32(1)
            _UniffiFfiConverterString.write(value.reason, buf)
            _UniffiFfiConverterOptionalString.write(value.detail, buf)


class StreamHandleProtocol(typing.Protocol):
    
    pass

class StreamHandle(StreamHandleProtocol):
    
    _handle: ctypes.c_uint64
    
    def __init__(self, *args, **kwargs):
        raise ValueError("This class has no default constructor")

    def __del__(self):
        # In case of partial initialization of instances.
        handle = getattr(self, "_handle", None)
        if handle is not None:
            _uniffi_rust_call(_UniffiLib.uniffi_strands_fn_free_streamhandle, handle)

    def _uniffi_clone_handle(self):
        return _uniffi_rust_call(_UniffiLib.uniffi_strands_fn_clone_streamhandle, self._handle)

    # Used by alternative constructors or any methods which return this type.
    @classmethod
    def _uniffi_make_instance(cls, handle):
        # Lightly yucky way to bypass the usual __init__ logic
        # and just create a new instance with the required handle.
        inst = cls.__new__(cls)
        inst._handle = handle
        return inst





class _UniffiFfiConverterTypeStreamHandle:
    @staticmethod
    def lift(value: int) -> StreamHandle:
        return StreamHandle._uniffi_make_instance(value)

    @staticmethod
    def check_lower(value: StreamHandle):
        if not isinstance(value, StreamHandle):
            raise TypeError("Expected StreamHandle instance, {} found".format(type(value).__name__))

    @staticmethod
    def lower(value: StreamHandle) -> ctypes.c_uint64:
        return value._uniffi_clone_handle()

    @classmethod
    def read(cls, buf: _UniffiRustBuffer) -> StreamHandle:
        ptr = buf.read_u64()
        if ptr == 0:
            raise InternalError("Raw handle value was null")
        return cls.lift(ptr)

    @classmethod
    def write(cls, value: StreamHandle, buf: _UniffiRustBuffer):
        buf.write_u64(cls.lower(value))

